SELECT cm.id, cm.game_type as gameType, cm.card_name as cardName, cm.card_number as cardNumber, cm.language, cm.manufacturer, cm.image_url as imageUrl, cm.description, cm.is_active as isActive, cm.hp, cm.illustrator_id as illustratorId, ill.name as illustrator, cm.expansion_code_id as expansionCodeId, ec.name as expansionCode, cm.block_id as blockId, blk.name as block, cs.id as cardSetId, cs.name as cardSetName, cc.id as categoryId, cc.display_name as categoryName, et.id as elementalTypeId, et.display_name as elementalTypeName, cr.id as rarityId, cr.display_name as rarity, es.id as evolutionStageId, es.name as evolutionStage, p.id as pokemonId, p.name as pokemonName FROM card_master cm LEFT JOIN card_set cs ON cm.card_set_id = cs.id LEFT JOIN card_category cc ON cm.category_id = cc.id LEFT JOIN elemental_type et ON cm.elemental_type_id = et.id LEFT JOIN card_rarity cr ON cm.rarity_id = cr.id LEFT JOIN evolution_stage es ON cm.evolution_stage_id = es.id LEFT JOIN pokemon p ON cm.pokemon_id = p.id LEFT JOIN illustrator ill ON cm.illustrator_id = ill.id LEFT JOIN card_expansion_code ec ON cm.expansion_code_id = ec.id LEFT JOIN card_block blk ON cm.block_id = blk.id
cm.is_active = true
AND cm.game_type = #{gameType}
AND cm.card_name LIKE CONCAT('%', #{cardName}, '%')
AND cm.card_set_id = #{cardSetId}
AND cm.card_number = #{cardNumber}
AND cr.display_name = #{rarity}
AND (cm.category_id = #{categoryId} OR cc.parent_id = #{categoryId})
AND cm.elemental_type_id = #{elementalTypeId}
AND es.name = #{evolutionStage}
AND cm.pokemon_id = #{pokemonId}
AND cm.block_id = #{blockId}
AND cm.expansion_code_id = #{expansionCodeId}
AND cm.illustrator_id = #{illustratorId}
ORDER BY cs.id DESC, cm.card_number ASC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
